-- Drop index "idx_links_redirect" from table: "links"
DROP INDEX "idx_links_redirect";
-- Modify "links" table
ALTER TABLE "links" ADD CONSTRAINT "links_created_via_check" CHECK (created_via = ANY (ARRAY['web'::text, 'api'::text, 'import'::text])), ADD CONSTRAINT "links_expiration_url_length" CHECK ((expiration_url IS NULL) OR (char_length(expiration_url) <= 2048)), ADD CONSTRAINT "links_max_clicks_positive" CHECK ((max_clicks IS NULL) OR (max_clicks > 0)), ADD CONSTRAINT "links_notes_length" CHECK ((notes IS NULL) OR (char_length(notes) <= 5000)), ADD CONSTRAINT "links_unique_click_count_non_negative" CHECK (unique_click_count >= 0), ADD COLUMN "starts_at" timestamptz NULL, ADD COLUMN "expiration_url" text NULL, ADD COLUMN "max_clicks" integer NULL, ADD COLUMN "utm_source" text NULL, ADD COLUMN "utm_medium" text NULL, ADD COLUMN "utm_campaign" text NULL, ADD COLUMN "utm_term" text NULL, ADD COLUMN "utm_content" text NULL, ADD COLUMN "og_title" text NULL, ADD COLUMN "og_description" text NULL, ADD COLUMN "og_image" text NULL, ADD COLUMN "unique_click_count" bigint NOT NULL DEFAULT 0, ADD COLUMN "notes" text NULL, ADD COLUMN "created_via" text NOT NULL DEFAULT 'web';
-- Create index "idx_links_redirect" to table: "links"
CREATE INDEX "idx_links_redirect" ON "links" ("short_code") INCLUDE ("dest_url", "is_active", "starts_at", "expires_at", "expiration_url", "max_clicks", "click_count") WHERE (deleted_at IS NULL);
